-- Migration 044 — SRD item seed + transactions backfill.
-- Spec-015 T035. Auto-generated by scripts/items-srd-codegen.ts —
-- DO NOT edit by hand; regenerate with:
--
--   npx tsx scripts/items-srd-codegen.ts > supabase/migrations/044_srd_items_seed.sql
--
-- Idempotency:
--   * Phase 1: NOT EXISTS guard on (campaign_id, fields->>'srd_slug')
--     — re-running adds no duplicates and never overwrites DM edits.
--   * Phase 2: only sets item_node_id where it is NULL — re-running
--     never re-points a row that's already linked.

begin;

-- ─────────────────────────── Phase 1: seed ───────────────────────────

do $$
declare
  c_rec record;
  type_id_v uuid;
  ins_count int;
begin
  for c_rec in select id, slug from campaigns order by created_at loop
    select id into type_id_v from node_types
      where campaign_id = c_rec.id and slug = 'item'
      limit 1;

    if type_id_v is null then
      raise notice 'Campaign % (%): no node_type=item, skipping seed',
        c_rec.slug, c_rec.id;
      continue;
    end if;

    with seed(
      srd_slug, title_ru, description_ru,
