      ('quarterstaff', 'Боевой посох', 'Простое универсальное оружие. 1d6 (одной), 1d8 (двумя).', 'weapon', null, 0.2, 4, 'versatile'),
      ('sickle', 'Серп', 'Простое лёгкое оружие. 1d4 рубящий.', 'weapon', null, 1, 2, '1-handed'),
