      ('alchemists-fire', 'Алхимический огонь', 'Метательная бутыль. 1d4 огня в начале хода цели, пока он не потушит огонь.', 'consumable', null, 50, 1, null),
      ('acid-vial', 'Кислота, бутыль', 'Метательная бутыль. 2d6 кислотой при попадании.', 'consumable', null, 25, 1, null),
      ('poison-basic-vial', 'Простой яд', 'Покрывает одно оружие. При попадании цель проходит спасбросок Тел DC 10 или получает 1d4 яда.', 'consumable', null, 100, 0, null),
      ('longsword-plus-1', '+1 длинный меч', '+1 к броску атаки и урона. 1d8 / 1d10 рубящий.', 'magic-item', 'uncommon', 1000, 3, 'versatile'),
      ('cloak-of-protection', 'Плащ защиты', '+1 к AC и спасброскам, пока носите. Требует настройки.', 'wondrous', 'uncommon', 4000, 1, 'cloak'),
      ('boots-of-elvenkind', 'Сапоги эльфов', 'Шаги бесшумны. Преимущество на скрытность бесшумных движений.', 'wondrous', 'uncommon', 4000, 1, 'boots'),
      ('bag-of-holding', 'Сумка хранения', 'Внутреннее пространство 64 куб. фута / 500 фунтов; снаружи весит 15 фунтов.', 'wondrous', 'uncommon', 4000, 15, null),
      ('ring-of-protection', 'Кольцо защиты', '+1 к AC и спасброскам. Требует настройки.', 'magic-item', 'rare', 8000, 0, 'ring'),
      ('amulet-of-health', 'Амулет здоровья', 'Телосложение становится 19. Требует настройки.', 'magic-item', 'rare', 8000, 1, 'amulet'),
      ('gauntlets-of-ogre-power', 'Перчатки силы огра', 'Сила становится 19. Требует настройки.', 'magic-item', 'uncommon', 4000, 2, 'gloves')
    ),
    typed_seed as (
      select
        srd_slug::text,
        title_ru::text,
        description_ru::text,
        category::text,
        rarity::text,
        price_gp::numeric,
        weight_lb::numeric,
        slot::text
      from seed
    ),
    inserted as (
      insert into nodes (campaign_id, type_id, title, fields)
      select
        c_rec.id,
        type_id_v,
        s.title_ru,
        jsonb_strip_nulls(jsonb_build_object(
          'srd_slug', s.srd_slug,
          'description', s.description_ru
        ))
      from typed_seed s
      where not exists (
        select 1 from nodes n
        where n.campaign_id = c_rec.id
          and n.fields->>'srd_slug' = s.srd_slug
      )
      returning id, fields->>'srd_slug' as srd_slug
    )
    insert into item_attributes (
      node_id, category_slug, rarity, price_gp, weight_lb,
      slot_slug, source_slug, availability_slug
    )
    select
      i.id, s.category, s.rarity, s.price_gp, s.weight_lb,
      s.slot, 'srd-5e', null
    from inserted i
    join typed_seed s on s.srd_slug = i.srd_slug
    on conflict (node_id) do nothing;

    get diagnostics ins_count = row_count;
    raise notice 'Campaign % (%): inserted % new SRD items',
      c_rec.slug, c_rec.id, ins_count;
  end loop;
end $$;

-- ─────────────────────────── Phase 2: backfill ───────────────────────────

do $$
declare
  c_rec record;
  bf_count int;
begin
  for c_rec in select id, slug from campaigns order by created_at loop
    update transactions tx
    set item_node_id = n.id
    from nodes n
    inner join item_attributes ia on ia.node_id = n.id
    where tx.campaign_id = c_rec.id
      and tx.kind = 'item'
      and tx.item_node_id is null
      and n.campaign_id = c_rec.id
      and ia.source_slug = 'srd-5e'
      and (
        lower(trim(tx.item_name)) = lower(trim(n.title))
        or lower(trim(coalesce(tx.item_name, ''))) = lower(coalesce(n.fields->>'srd_slug', ''))
      );

    get diagnostics bf_count = row_count;
    raise notice 'Campaign % (%): backfilled % transactions',
      c_rec.slug, c_rec.id, bf_count;
  end loop;
end $$;

commit;

